namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple and delicious traditional Italian pizza.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Preheat oven to 475°F (245°C).", "Roll out dough on a floured surface.", "Spread crushed tomatoes over the dough.", "Tear mozzarella and distribute evenly.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
                TotalRatings = 12, RatingSum = 52
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy Roman pasta made with eggs, cheese, and pancetta.",
                Ingredients = ["400g spaghetti", "200g pancetta", "4 egg yolks", "100g Pecorino Romano", "Black pepper"],
                Steps = ["Cook spaghetti in salted boiling water.", "Fry pancetta until crispy.", "Whisk egg yolks with grated Pecorino and pepper.", "Drain pasta, reserving some water.", "Toss hot pasta with pancetta, then mix in egg mixture off heat.", "Serve immediately with extra cheese and pepper."],
                TotalRatings = 8, RatingSum = 38
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken pieces in a rich, spiced tomato-cream sauce.",
                Ingredients = ["500g chicken breast", "Yogurt", "Garam masala", "Tomato puree", "Heavy cream", "Onion", "Garlic", "Ginger"],
                Steps = ["Marinate chicken in yogurt and spices for 2 hours.", "Grill or pan-fry chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato puree and spices, simmer 15 minutes.", "Stir in cream and add chicken pieces.", "Simmer 10 minutes and serve with rice or naan."],
                TotalRatings = 15, RatingSum = 68
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
                Description = "A vibrant stir-fried noodle dish with crunchy vegetables.",
                Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Carrots", "Peanuts", "Lime", "Fish sauce", "Tamarind paste", "Brown sugar"],
                Steps = ["Soak rice noodles in warm water for 20 minutes.", "Mix tamarind paste, fish sauce, and brown sugar for the sauce.", "Stir-fry cubed tofu until golden.", "Add vegetables and stir-fry 2 minutes.", "Add drained noodles and sauce, toss well.", "Serve topped with crushed peanuts and lime wedges."],
                TotalRatings = 6, RatingSum = 25
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef tacos with fresh toppings.",
                Ingredients = ["Ground beef", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Taco seasoning"],
                Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm taco shells in the oven.", "Fill shells with beef.", "Top with shredded lettuce, diced tomato, cheese, and sour cream.", "Serve with salsa and lime."],
                TotalRatings = 10, RatingSum = 42
            },
            new Recipe
            {
                Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts",
                Description = "Rich individual chocolate cakes with a molten center.",
                Ingredients = ["200g dark chocolate", "100g butter", "3 eggs", "100g sugar", "50g flour", "Butter for ramekins"],
                Steps = ["Preheat oven to 425°F (220°C).", "Melt chocolate and butter together.", "Whisk eggs and sugar until thick.", "Fold chocolate mixture into eggs, then fold in flour.", "Pour into buttered ramekins.", "Bake 12-14 minutes until edges are set but center is soft.", "Invert onto plates and serve immediately."],
                TotalRatings = 20, RatingSum = 95
            },
        ];
        _nextId = 7;
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public Recipe AddRecipe(string title, string category, string description, List<string> ingredients, List<string> steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Description = description,
            Ingredients = ingredients,
            Steps = steps
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

