@page "/category/{CategoryName}"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<h1>@CategoryName Recipes</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (Recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <div class="mb-2">
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                                }
                            </span>
                            <small class="text-muted">(@recipe.TotalRatings ratings)</small>
                        </div>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeCommunity.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe")</PageTitle>

@if (Recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <p class="lead">@Recipe.Description</p>

    <StarRating RecipeId="Recipe.Id" CurrentAverage="Recipe.AverageRating" TotalRatings="Recipe.TotalRatings" />

    <div class="row mt-4">
        <div class="col-md-5">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">🥘 Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in Recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-7">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">📋 Steps</h5></div>
                <div class="card-body">
                    <ol>
                        @foreach (var step in Recipe.Steps)
                        {
                            <li class="mb-2">@step</li>
                        }
                    </ol>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeCommunity.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<div class="my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button"
              style="cursor:pointer; font-size:1.5rem;"
              class="@(star <= (UserRating ?? (int)Math.Round(CurrentAverage)) ? "text-warning" : "text-muted")"
              @onclick="() => Rate(star)">★</span>
    }
    <span class="ms-2 text-muted">
        @if (UserRating.HasValue)
        {
            <text>You rated @UserRating ★ — Thank you!</text>
        }
        else
        {
            <text>@CurrentAverage.ToString("0.0") avg (@TotalRatings ratings)</text>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int TotalRatings { get; set; }

    private int? UserRating { get; set; }

    private void Rate(int stars)
    {
        if (UserRating.HasValue) return;
        RecipeService.AddRating(RecipeId, stars);
        UserRating = stars;
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            TotalRatings = recipe.TotalRatings;
        }
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h1>📝 Submit a Recipe</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>Recipe submitted!</h4>
        <p>Your recipe "<strong>@Title</strong>" has been added.</p>
        <a href="recipe/@NewRecipeId" class="btn btn-primary me-2">View Recipe</a>
        <button class="btn btn-outline-secondary" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label class="form-label">Title</label>
            <InputText class="form-control" @bind-Value="Title" required />
        </div>

        <div class="mb-3">
            <label class="form-label">Category</label>
            <InputSelect class="form-select" @bind-Value="Category">
                <option value="">-- Select --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Thai">Thai</option>
                <option value="Mexican">Mexican</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label class="form-label">Description</label>
            <InputTextArea class="form-control" @bind-Value="Description" rows="2" />
        </div>

        <div class="mb-3">
            <label class="form-label">Ingredients (one per line)</label>
            <InputTextArea class="form-control" @bind-Value="IngredientsText" rows="5" required />
        </div>

        <div class="mb-3">
            <label class="form-label">Steps (one per line)</label>
            <InputTextArea class="form-control" @bind-Value="StepsText" rows="5" required />
        </div>

        <button type="submit" class="btn btn-success" disabled="@(!IsValid)">Submit Recipe</button>
    </EditForm>
}

@code {
    private string Title { get; set; } = string.Empty;
    private string Category { get; set; } = string.Empty;
    private string Description { get; set; } = string.Empty;
    private string IngredientsText { get; set; } = string.Empty;
    private string StepsText { get; set; } = string.Empty;
    private bool Submitted { get; set; }
    private int NewRecipeId { get; set; }

    private bool IsValid =>
        !string.IsNullOrWhiteSpace(Title) &&
        !string.IsNullOrWhiteSpace(Category) &&
        !string.IsNullOrWhiteSpace(IngredientsText) &&
        !string.IsNullOrWhiteSpace(StepsText);

    private void HandleSubmit()
    {
        if (!IsValid) return;

        var ingredients = IngredientsText.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList();
        var steps = StepsText.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList();

        var recipe = RecipeService.AddRecipe(Title, Category, Description, ingredients, steps);
        NewRecipeId = recipe.Id;
        Submitted = true;
    }

    private void Reset()
    {
        Title = string.Empty;
        Category = string.Empty;
        Description = string.Empty;
        IngredientsText = string.Empty;
        StepsText = string.Empty;
        Submitted = false;
    }
}

