        </div>

        <div class="mb-3">
            <label class="form-label">Steps (one per line)</label>
            <InputTextArea class="form-control" @bind-Value="StepsText" rows="5" required />
        </div>

        <button type="submit" class="btn btn-success" disabled="@(!IsValid)">Submit Recipe</button>
    </EditForm>
}

@code {
    private string Title { get; set; } = string.Empty;
    private string Category { get; set; } = string.Empty;
    private string Description { get; set; } = string.Empty;
    private string IngredientsText { get; set; } = string.Empty;
    private string StepsText { get; set; } = string.Empty;
    private bool Submitted { get; set; }
    private int NewRecipeId { get; set; }

    private bool IsValid =>
        !string.IsNullOrWhiteSpace(Title) &&
        !string.IsNullOrWhiteSpace(Category) &&
        !string.IsNullOrWhiteSpace(IngredientsText) &&
        !string.IsNullOrWhiteSpace(StepsText);

    private void HandleSubmit()
    {
        if (!IsValid) return;

        var ingredients = IngredientsText.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList();
        var steps = StepsText.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList();

        var recipe = RecipeService.AddRecipe(Title, Category, Description, ingredients, steps);
        NewRecipeId = recipe.Id;
        Submitted = true;
    }

    private void Reset()
    {
        Title = string.Empty;
        Category = string.Empty;
        Description = string.Empty;
        IngredientsText = string.Empty;
        StepsText = string.Empty;
        Submitted = false;
    }
}
